describe('fuzz: while with break and continue', () => {
  const code = `#include <iostream>
using namespace std;
int main() {
    int i = 0;
    int sum = 0;
    while (i < 100) {
        i = i + 1;
        if (i % 5 != 0) {
            continue;
        }
        if (i > 30) {
            break;
        }
        sum = sum + i;
    }
    cout << sum << endl;
    cout << i << endl;
    return 0;
}`

  it('executes correctly', async () => {
    const interp = await runCode(code)
    const out = interp.getOutput().join('')
    expect(out).toContain('105')  // 5+10+15+20+25+30
    expect(out).toContain('35')   // breaks when i=35 (first multiple of 5 > 30)
  })

  it('roundtrip is stable', () => {
    const gen1 = roundTrip(code)
    const gen2 = roundTrip(gen1)
    expect(gen1).toBe(gen2)
  })
})

